/* ============================================================
   SOLARIS — Agency-as-a-Service
   Visual system: solar / CLI hybrid. Deep warm black,
   amber-solar accents, monospaced operating signal.
   ============================================================ */

:root {
  /* Solar palette (default — SOLARIS franchise) */
  --bg: #0b0907;
  --bg-2: #100c08;
  --surface: #15110b;
  --surface-2: #1b1610;
  --line: #2a2118;
  --line-2: #3a2f22;
  --ink: #f4ecdc;
  --ink-2: #c5b59a;
  --ink-3: #8a7a60;
  --ink-4: #5a4d3a;
  --accent: #e89b5c;        /* solar amber */
  --accent-2: #f0c987;      /* corona */
  --flare: #c4432b;         /* solar red */
  --mint: #7cd9a8;          /* stable signal */
  --violet: #9d7cd9;        /* secondary signal */
  --core: #ffd89e;          /* sun core */

  --font-display: "Instrument Serif", "Times New Roman", serif;
  --font-sans: "Geist", "Helvetica Neue", system-ui, sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, "SF Mono", monospace;

  --pad-x: clamp(20px, 5vw, 80px);
  --r: 6px;
}

/* NEXUS — Citadel / cool ink / forensic blue */
[data-icp="nexus"] {
  --bg: #07090d;
  --bg-2: #0a0d13;
  --surface: #0e131c;
  --surface-2: #131a26;
  --line: #1d2638;
  --line-2: #2a374f;
  --ink: #e8eef7;
  --ink-2: #a8b4c8;
  --ink-3: #6c7a92;
  --ink-4: #3f4a5d;
  --accent: #6a92d4;
  --accent-2: #a5c0ea;
  --flare: #d4a36a;        /* gilt accent for legal */
  --core: #c8d8f0;
}

/* ORBITER — Field / dust / industrial */
[data-icp="orbiter"] {
  --bg: #0c0a08;
  --bg-2: #110e0a;
  --surface: #181410;
  --surface-2: #1f1a14;
  --line: #2e261d;
  --line-2: #3e3528;
  --ink: #f0e8d8;
  --ink-2: #c0b294;
  --ink-3: #82765e;
  --ink-4: #514735;
  --accent: #d97f3a;
  --accent-2: #e6a460;
  --flare: #8a3e1e;
  --mint: #b8c879;
  --core: #f0c887;
}

[data-density="compact"] { --pad-x: clamp(16px, 3vw, 56px); }
[data-density="spacious"] { --pad-x: clamp(28px, 7vw, 120px); }

/* ----------- Reset ----------- */
*, *::before, *::after { box-sizing: border-box; }
html, body { margin: 0; padding: 0; }
body {
  background: var(--bg);
  color: var(--ink);
  font-family: var(--font-sans);
  font-feature-settings: "ss01", "ss02", "cv11";
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  overflow-x: hidden;
  line-height: 1.5;
}
img { max-width: 100%; display: block; }
a { color: inherit; text-decoration: none; }
button { font: inherit; color: inherit; background: transparent; border: 0; cursor: pointer; }

/* Selection */
::selection { background: var(--accent); color: var(--bg); }

/* ----------- Type primitives ----------- */
.eyebrow {
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--accent);
  display: inline-flex;
  align-items: center;
  gap: 10px;
}
.eyebrow::before {
  content: "";
  width: 14px; height: 1px;
  background: var(--accent);
  display: inline-block;
}
.display {
  font-family: var(--font-display);
  font-weight: 400;
  font-style: normal;
  letter-spacing: -0.01em;
  line-height: 0.95;
  color: var(--ink);
}
.display em {
  font-style: italic;
  color: var(--accent-2);
}
.mono { font-family: var(--font-mono); font-size: 13px; letter-spacing: 0.01em; }

.muted { color: var(--ink-2); }
.dim { color: var(--ink-3); }
.faint { color: var(--ink-4); }

/* ----------- Page shell ----------- */
.page {
  min-height: 100vh;
  background:
    radial-gradient(1200px 800px at 80% -10%, rgba(232, 155, 92, 0.06), transparent 60%),
    radial-gradient(900px 600px at 10% 30%, rgba(196, 67, 43, 0.04), transparent 60%),
    var(--bg);
  position: relative;
}

.section {
  padding: clamp(80px, 10vw, 140px) var(--pad-x);
  position: relative;
  border-top: 1px solid var(--line);
}
.section:first-of-type { border-top: 0; }
.section-head {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;
  margin-bottom: clamp(40px, 5vw, 72px);
  max-width: 1080px;
}
.section-head h2 { margin: 0; }

/* ----------- Top bar ----------- */
.topbar {
  position: fixed;
  inset: 0 0 auto 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px var(--pad-x);
  z-index: 50;
  background: linear-gradient(180deg, var(--bg) 0%, color-mix(in oklab, var(--bg) 70%, transparent) 80%, transparent 100%);
  backdrop-filter: blur(6px);
}
.brand {
  display: flex;
  align-items: center;
  gap: 12px;
}
.brand-mark {
  width: 26px; height: 26px;
  position: relative;
}
.brand-mark::before {
  content: "";
  position: absolute; inset: 0;
  border-radius: 50%;
  background: radial-gradient(circle at 35% 30%, var(--core), var(--accent) 55%, var(--flare) 90%);
  box-shadow: 0 0 18px color-mix(in oklab, var(--accent) 60%, transparent);
}
.brand-mark::after {
  content: "";
  position: absolute; inset: -5px;
  border: 1px solid color-mix(in oklab, var(--accent) 30%, transparent);
  border-radius: 50%;
}
.brand-name {
  font-family: var(--font-display);
  font-size: 22px;
  letter-spacing: 0.02em;
}
.brand-name b { font-weight: 400; }
.brand-tag {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.2em;
  color: var(--ink-3);
  text-transform: uppercase;
  border-left: 1px solid var(--line);
  padding-left: 12px;
  margin-left: 4px;
}

.nav {
  display: flex;
  gap: 28px;
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--ink-2);
}
.nav a:hover { color: var(--ink); }
.nav a .num { color: var(--ink-4); margin-right: 6px; }

.top-cta {
  font-family: var(--font-mono);
  font-size: 12px;
  padding: 8px 14px;
  border: 1px solid var(--line-2);
  border-radius: 999px;
  color: var(--ink);
  transition: 0.2s;
  display: inline-flex; gap: 8px; align-items: center;
}
.top-cta:hover { border-color: var(--accent); color: var(--accent); }
.top-cta .pulse {
  width: 6px; height: 6px;
  background: var(--mint);
  border-radius: 50%;
  box-shadow: 0 0 10px var(--mint);
  animation: pulse 2s infinite;
}
@keyframes pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.5; transform: scale(0.7); }
}

/* ----------- Hero ----------- */
.hero {
  min-height: 100vh;
  padding: 140px var(--pad-x) 80px;
  display: grid;
  grid-template-columns: 1.1fr 1fr;
  gap: 60px;
  align-items: center;
  position: relative;
  overflow: hidden;
}
@media (max-width: 980px) {
  .hero { grid-template-columns: 1fr; min-height: auto; }
}

.hero-copy { max-width: 640px; position: relative; z-index: 2; }
.hero h1 {
  font-size: clamp(48px, 7.2vw, 104px);
  margin: 24px 0 28px;
  text-wrap: balance;
}
.hero .sub {
  font-size: clamp(16px, 1.3vw, 19px);
  color: var(--ink-2);
  max-width: 540px;
  text-wrap: pretty;
}
.hero-meta {
  margin-top: 40px;
  display: flex;
  gap: 32px;
  flex-wrap: wrap;
}
.hero-meta .stat {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.hero-meta .v {
  font-family: var(--font-display);
  font-size: 32px;
  color: var(--ink);
}
.hero-meta .l {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--ink-3);
}

.hero-cta-row {
  margin-top: 44px;
  display: flex;
  align-items: center;
  gap: 18px;
  flex-wrap: wrap;
}
.btn-primary {
  font-family: var(--font-mono);
  font-size: 13px;
  letter-spacing: 0.04em;
  padding: 14px 22px;
  background: var(--accent);
  color: var(--bg);
  border-radius: 4px;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  transition: 0.2s;
  font-weight: 500;
}
.btn-primary:hover { background: var(--accent-2); }
.btn-primary .arrow { font-family: var(--font-mono); }

.btn-ghost {
  font-family: var(--font-mono);
  font-size: 13px;
  letter-spacing: 0.04em;
  padding: 13px 20px;
  border: 1px solid var(--line-2);
  border-radius: 4px;
  display: inline-flex;
  gap: 10px;
  align-items: center;
  transition: 0.2s;
}
.btn-ghost:hover { border-color: var(--accent); color: var(--accent); }

/* ----------- Orbital diagram (hero) ----------- */
.orbital-stage {
  position: relative;
  aspect-ratio: 1 / 1;
  width: 100%;
  max-width: 640px;
  justify-self: end;
  z-index: 1;
}
@media (max-width: 980px) {
  .orbital-stage { justify-self: center; max-width: 480px; }
}

.orbital-svg {
  width: 100%;
  height: 100%;
  overflow: visible;
}
.orbital-ring { fill: none; stroke: var(--line); stroke-width: 1; }
.orbital-ring-soft { fill: none; stroke: var(--line); stroke-width: 1; stroke-dasharray: 2 6; opacity: 0.6; }

.orbital-sun {
  fill: url(#sunGrad);
  filter: url(#sunGlow);
}

.orbital-planet {
  fill: var(--surface-2);
  stroke: var(--line-2);
  stroke-width: 1;
  transition: 0.3s;
}
.orbital-planet.active {
  fill: var(--accent);
  stroke: var(--accent-2);
}
.orbital-label {
  font-family: var(--font-mono);
  font-size: 10px;
  fill: var(--ink-2);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}
.orbital-label.active { fill: var(--ink); }

.orbit-rotating {
  transform-origin: center center;
  animation: rotate-slow 120s linear infinite;
}
.orbit-rotating-rev {
  transform-origin: center center;
  animation: rotate-slow-rev 180s linear infinite;
}
@keyframes rotate-slow { to { transform: rotate(360deg); } }
@keyframes rotate-slow-rev { to { transform: rotate(-360deg); } }

.orbital-readout {
  position: absolute;
  bottom: 6%;
  left: 4%;
  background: color-mix(in oklab, var(--bg) 85%, transparent);
  border: 1px solid var(--line);
  border-radius: 4px;
  padding: 10px 14px;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--ink-2);
  backdrop-filter: blur(8px);
  min-width: 180px;
}
.orbital-readout .k { color: var(--ink-3); }
.orbital-readout .v { color: var(--ink); }

/* hero grid backdrop */
.hero-grid {
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(var(--line) 1px, transparent 1px),
    linear-gradient(90deg, var(--line) 1px, transparent 1px);
  background-size: 80px 80px;
  background-position: -1px -1px;
  opacity: 0.25;
  mask-image: radial-gradient(ellipse at 70% 60%, black 0%, transparent 70%);
  pointer-events: none;
}

/* ----------- AaaS section ----------- */
.aaas {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 60px;
  align-items: start;
}
@media (max-width: 900px) { .aaas { grid-template-columns: 1fr; } }

.aaas h2 {
  font-size: clamp(36px, 5vw, 72px);
  margin: 0;
  text-wrap: balance;
}
.aaas-prose p {
  font-size: 18px;
  color: var(--ink-2);
  margin: 0 0 20px;
  text-wrap: pretty;
}

.compare {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1px;
  background: var(--line);
  border: 1px solid var(--line);
  border-radius: 4px;
  overflow: hidden;
  margin-top: 32px;
}
.compare-cell {
  background: var(--surface);
  padding: 20px;
}
.compare-cell.bad { color: var(--ink-3); }
.compare-cell h4 {
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  margin: 0 0 14px;
  color: var(--ink-4);
}
.compare-cell.good h4 { color: var(--accent); }
.compare-cell ul { list-style: none; padding: 0; margin: 0; }
.compare-cell li {
  font-family: var(--font-mono);
  font-size: 12px;
  padding: 8px 0;
  border-bottom: 1px dashed var(--line);
  display: flex;
  gap: 10px;
  align-items: flex-start;
}
.compare-cell li:last-child { border-bottom: 0; }
.compare-cell .sym { color: var(--ink-4); min-width: 14px; }
.compare-cell.good .sym { color: var(--accent); }

/* ----------- Stack L0/L1/L2 ----------- */
.stack-wrap {
  display: grid;
  grid-template-columns: 1.1fr 1fr;
  gap: 60px;
  align-items: center;
}
@media (max-width: 980px) { .stack-wrap { grid-template-columns: 1fr; } }

.stack-3d {
  position: relative;
  aspect-ratio: 5 / 4;
  perspective: 1400px;
}
.stack-layer {
  position: absolute;
  left: 8%;
  right: 8%;
  height: 28%;
  border: 1px solid var(--line-2);
  background: linear-gradient(180deg, var(--surface-2), var(--surface));
  border-radius: 8px;
  padding: 18px 22px;
  transform-style: preserve-3d;
  transform: rotateX(58deg) rotateZ(-22deg);
  box-shadow: 0 30px 60px -20px rgba(0,0,0,0.6);
  cursor: pointer;
  transition: 0.4s cubic-bezier(.2,.7,.2,1);
}
.stack-layer:hover {
  transform: rotateX(58deg) rotateZ(-22deg) translateZ(20px);
  border-color: var(--accent);
}
.stack-layer.l0 { top: 60%; }
.stack-layer.l1 { top: 36%; }
.stack-layer.l2 { top: 12%; }

.stack-layer .tag {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.2em;
  color: var(--accent);
  text-transform: uppercase;
}
.stack-layer .name {
  font-family: var(--font-display);
  font-size: 22px;
  margin-top: 6px;
}
.stack-layer .pilot {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--ink-3);
  margin-top: 4px;
}

.stack-list { display: flex; flex-direction: column; gap: 1px; }
.stack-row {
  background: var(--surface);
  border: 1px solid var(--line);
  padding: 24px 28px;
  border-radius: 4px;
  display: grid;
  grid-template-columns: 60px 1fr auto;
  gap: 24px;
  align-items: center;
  transition: 0.2s;
}
.stack-row:hover { border-color: var(--line-2); background: var(--surface-2); }
.stack-row .layer-id {
  font-family: var(--font-display);
  font-size: 40px;
  color: var(--accent);
  line-height: 1;
}
.stack-row .layer-body h4 {
  margin: 0 0 4px;
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 400;
}
.stack-row .layer-body p {
  margin: 6px 0 0;
  font-size: 14px;
  color: var(--ink-2);
}
.stack-row .pilot-pill {
  font-family: var(--font-mono);
  font-size: 11px;
  padding: 6px 10px;
  border: 1px solid var(--line-2);
  border-radius: 999px;
  color: var(--ink-2);
  white-space: nowrap;
}

/* ----------- Margin Shield ----------- */
.shield-wrap {
  display: grid;
  grid-template-columns: 1fr 1.2fr;
  gap: 60px;
  align-items: center;
}
@media (max-width: 980px) { .shield-wrap { grid-template-columns: 1fr; } }

.shield-card {
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 8px;
  padding: 28px;
  position: relative;
  overflow: hidden;
}
.shield-card .label-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 18px;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--ink-3);
  text-transform: uppercase;
  letter-spacing: 0.15em;
}
.shield-card .label-row .live {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  color: var(--mint);
}
.shield-card .label-row .live::before {
  content: "";
  width: 6px; height: 6px;
  background: var(--mint);
  border-radius: 50%;
  box-shadow: 0 0 8px var(--mint);
  animation: pulse 2s infinite;
}

.shield-chart {
  position: relative;
  height: 240px;
  border-bottom: 1px solid var(--line);
  border-left: 1px solid var(--line);
  margin: 8px 0 16px;
}
.shield-threshold {
  position: absolute;
  left: 0; right: 0;
  border-top: 1px dashed var(--flare);
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--flare);
  letter-spacing: 0.1em;
}
.shield-threshold::after {
  content: attr(data-label);
  position: absolute;
  right: 0;
  top: -16px;
}

.shield-bar {
  position: absolute;
  bottom: 0;
  width: 6%;
  background: linear-gradient(180deg, var(--accent), color-mix(in oklab, var(--accent) 60%, transparent));
  transition: height 0.4s cubic-bezier(.2,.7,.2,1);
  border-radius: 1px 1px 0 0;
}
.shield-bar.brute {
  background: linear-gradient(180deg, var(--flare), color-mix(in oklab, var(--flare) 40%, transparent));
}

.shield-readouts {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 1px;
  background: var(--line);
  border: 1px solid var(--line);
  border-radius: 4px;
  overflow: hidden;
  margin-top: 16px;
}
.shield-readout {
  background: var(--surface-2);
  padding: 14px;
}
.shield-readout .k {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--ink-3);
  text-transform: uppercase;
  letter-spacing: 0.15em;
}
.shield-readout .v {
  font-family: var(--font-display);
  font-size: 28px;
  color: var(--ink);
  margin-top: 4px;
}
.shield-readout .v.good { color: var(--mint); }
.shield-readout .v.bad { color: var(--flare); }

.shield-control {
  margin-top: 18px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.shield-control .row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--ink-2);
  text-transform: uppercase;
  letter-spacing: 0.12em;
}
.shield-slider {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 2px;
  background: var(--line-2);
  border-radius: 0;
  outline: none;
}
.shield-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 14px;
  height: 14px;
  background: var(--accent);
  border-radius: 0;
  cursor: pointer;
  border: 2px solid var(--bg);
}
.shield-slider::-moz-range-thumb {
  width: 14px;
  height: 14px;
  background: var(--accent);
  border: 2px solid var(--bg);
  border-radius: 0;
  cursor: pointer;
}

.shield-router {
  display: grid;
  grid-template-columns: 1fr;
  gap: 10px;
  margin-top: 18px;
}
.router-row {
  display: grid;
  grid-template-columns: 100px 1fr 80px;
  gap: 14px;
  align-items: center;
  font-family: var(--font-mono);
  font-size: 11px;
}
.router-row .model { color: var(--ink-2); }
.router-row .bar {
  height: 4px;
  background: var(--line);
  border-radius: 0;
  overflow: hidden;
}
.router-row .bar > div {
  height: 100%;
  background: var(--accent);
  transition: width 0.4s;
}
.router-row.cheap .bar > div { background: var(--mint); }
.router-row.mid .bar > div { background: var(--accent); }
.router-row.heavy .bar > div { background: var(--flare); }
.router-row .pct { color: var(--ink); text-align: right; }

/* ----------- 8 Domains (Wheel) ----------- */
.wheel-wrap {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 60px;
  align-items: center;
}
@media (max-width: 980px) { .wheel-wrap { grid-template-columns: 1fr; } }

.wheel {
  position: relative;
  aspect-ratio: 1/1;
  width: 100%;
  max-width: 580px;
}
.wheel-detail {
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 6px;
  padding: 32px;
  min-height: 360px;
}
.wheel-detail .domain-num {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.2em;
  color: var(--accent);
}
.wheel-detail h3 {
  font-family: var(--font-display);
  font-size: 44px;
  margin: 8px 0 4px;
  font-weight: 400;
}
.wheel-detail .role {
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--ink-3);
  margin-bottom: 24px;
}
.wheel-detail .description {
  font-size: 16px;
  color: var(--ink-2);
  text-wrap: pretty;
